module top_module(q, d, clk, enable, reset);parameter
        width = 32,
        reset_value = 0;

    output reg    [(width-1):0] q;
    input  [(width-1):0] d;
    input  clk, enable, reset;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
        if (reset == 1'b1)
            q <= reset_value;
        else if (enable == 1'b1)
            q <= d;endmodule
